import{_ as s,o as n,c as e,ag as t}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Graph Functions","description":"","frontmatter":{},"headers":[],"relativePath":"guide/fusion/graph.md","filePath":"guide/fusion/graph.md"}'),p={name:"guide/fusion/graph.md"};function i(l,a,r,o,h,d){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="graph-functions" tabindex="-1">Graph Functions <a class="header-anchor" href="#graph-functions" aria-label="Permalink to &quot;Graph Functions&quot;">​</a></h1><p>Graph functions compile <strong>entire function bodies</strong> as optimized compute graphs. The compiler automatically fuses operations, eliminates intermediate allocations, and dispatches to the optimal hardware — GPU or SIMD.</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Add the \`graph\` keyword before your function name</span></span>
<span class="line"><span>graph fn dot(a: [f32; N], b: [f32; N]): f32 {</span></span>
<span class="line"><span>    return &lt;+ (a * b);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fn main(): i32 {</span></span>
<span class="line"><span>    let x = [2.0f32; 100000];</span></span>
<span class="line"><span>    let y = [3.0f32; 100000];</span></span>
<span class="line"><span>    let result = dot(x, y);  // → GPU dispatch on Apple Silicon</span></span>
<span class="line"><span>    $println(&quot;dot = {}&quot;, result);</span></span>
<span class="line"><span>    return 0;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>What happens behind the scenes:</strong></p><ol><li>Compiler parses the entire <code>graph</code> body into a computation graph fn (SIR DAG)</li><li>Fusion pass merges <code>a * b</code> + <code>&lt;+</code> into a single fused operation</li><li>Dispatch policy checks data size and hardware: <ul><li><strong>100K floats on Apple M2</strong> → Metal GPU compute kernel</li><li><strong>100 floats</strong> → SIMD vectorized loop (AVX-512 / NEON)</li></ul></li><li>Zero intermediate arrays allocated</li></ol><h2 id="why-graph-functions" tabindex="-1">Why Graph Functions? <a class="header-anchor" href="#why-graph-functions" aria-label="Permalink to &quot;Why Graph Functions?&quot;">​</a></h2><h3 id="without-graph" tabindex="-1">Without <code>graph</code> <a class="header-anchor" href="#without-graph" aria-label="Permalink to &quot;Without \`graph\`&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn slow_normalize(x: [f32; N]): [f32; N] {</span></span>
<span class="line"><span>    let mean = &lt;+ x / N;              // Loop 1 + temp scalar</span></span>
<span class="line"><span>    let centered = x - mean;           // Loop 2 + temp array [N]</span></span>
<span class="line"><span>    let sq = centered * centered;      // Loop 3 + temp array [N]</span></span>
<span class="line"><span>    let variance = &lt;+ sq / N;         // Loop 4 + temp scalar</span></span>
<span class="line"><span>    return centered / sqrt(variance);  // Loop 5 + temp array [N]</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>// 5 loops, 3 temporary arrays, 5× cache misses</span></span></code></pre></div><h3 id="with-graph" tabindex="-1">With <code>graph</code> <a class="header-anchor" href="#with-graph" aria-label="Permalink to &quot;With \`graph\`&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>graph fn normalize(x: [f32; N]): [f32; N] {</span></span>
<span class="line"><span>    let mean = &lt;+ x / N;</span></span>
<span class="line"><span>    let centered = x - mean;</span></span>
<span class="line"><span>    let variance = &lt;+ (centered * centered) / N;</span></span>
<span class="line"><span>    return centered / sqrt(variance);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>// GPU: 2 kernels (fused reduce + fused elementwise), 0 temp arrays</span></span>
<span class="line"><span>// SIMD: 2 vectorized loops, 0 temp arrays, register-only intermediates</span></span></code></pre></div><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>Graph functions support all Vex array and tensor operations:</p><h3 id="array-operations" tabindex="-1">Array Operations <a class="header-anchor" href="#array-operations" aria-label="Permalink to &quot;Array Operations&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>graph fn example(a: [f32; N], b: [f32; N]): [f32; N] {</span></span>
<span class="line"><span>    let sum = a + b;           // elementwise add</span></span>
<span class="line"><span>    let prod = a * b;          // elementwise multiply</span></span>
<span class="line"><span>    let scaled = a * 2.0;      // scalar broadcast</span></span>
<span class="line"><span>    let total = &lt;+ a;          // reduction (sum)</span></span>
<span class="line"><span>    let maximum = &gt;?| a;       // reduction (max)</span></span>
<span class="line"><span>    return sum;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="matrix-operations" tabindex="-1">Matrix Operations <a class="header-anchor" href="#matrix-operations" aria-label="Permalink to &quot;Matrix Operations&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>graph fn matmul_chain(a: [f32; M, K], b: [f32; K, N], c: [f32; N, P]): [f32; M, P] {</span></span>
<span class="line"><span>    let ab = a &lt;*&gt; b;          // matrix multiply</span></span>
<span class="line"><span>    return ab &lt;*&gt; c;           // chained matmul</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="math-functions" tabindex="-1">Math Functions <a class="header-anchor" href="#math-functions" aria-label="Permalink to &quot;Math Functions&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>graph fn activation(x: [f32; N]): [f32; N] {</span></span>
<span class="line"><span>    return exp(x) / (1.0 + exp(x));  // sigmoid, all fused</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="control-flow" tabindex="-1">Control Flow <a class="header-anchor" href="#control-flow" aria-label="Permalink to &quot;Control Flow&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>graph fn relu(x: [f32; N]): [f32; N] {</span></span>
<span class="line"><span>    if x &gt; 0.0 {</span></span>
<span class="line"><span>        return x;</span></span>
<span class="line"><span>    } else {</span></span>
<span class="line"><span>        return 0.0;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>graph fn transformer(x: [f32; N], layers: [[f32; N, N]; 12]): [f32; N] {</span></span>
<span class="line"><span>    let! out = x;</span></span>
<span class="line"><span>    for i in 0..12 {       // compile-time unrolled</span></span>
<span class="line"><span>        out = out &lt;*&gt; layers[i];</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    return out;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="nested-graph-functions" tabindex="-1">Nested Graph Functions <a class="header-anchor" href="#nested-graph-functions" aria-label="Permalink to &quot;Nested Graph Functions&quot;">​</a></h2><p>Graph functions can call other graph fn functions. The compiler <strong>inlines</strong> the callee&#39;s computation graph fn into the caller&#39;s, enabling cross-function fusion:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>graph fn softmax(x: [f32; N]): [f32; N] {</span></span>
<span class="line"><span>    let max_val = &gt;?| x;</span></span>
<span class="line"><span>    let shifted = x - max_val;</span></span>
<span class="line"><span>    let exp_vals = exp(shifted);</span></span>
<span class="line"><span>    let sum_val = &lt;+ exp_vals;</span></span>
<span class="line"><span>    return exp_vals / sum_val;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>graph fn attention(q: [f32; N], k: [f32; N], v: [f32; N]): [f32; N] {</span></span>
<span class="line"><span>    let scores = q &lt;*&gt; k.T / sqrt(N);</span></span>
<span class="line"><span>    let weights = softmax(scores);  // ← inlined and fused!</span></span>
<span class="line"><span>    return weights &lt;*&gt; v;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="hardware-dispatch" tabindex="-1">Hardware Dispatch <a class="header-anchor" href="#hardware-dispatch" aria-label="Permalink to &quot;Hardware Dispatch&quot;">​</a></h2><p>The compiler automatically selects the best execution target:</p><table tabindex="0"><thead><tr><th>Data Size</th><th>Target</th><th>Why</th></tr></thead><tbody><tr><td>&lt; 2,048 elements</td><td><strong>Scalar</strong></td><td>Not worth vectorizing</td></tr><tr><td>2,048 – 50,000</td><td><strong>SIMD</strong> (AVX-512 / NEON)</td><td>CPU cache-friendly</td></tr><tr><td>≥ 50,000 (Apple UMA)</td><td><strong>GPU</strong> (Metal)</td><td>Zero-copy shared memory</td></tr><tr><td>≥ 1,000,000 (discrete)</td><td><strong>GPU</strong> (CUDA/ROCm)</td><td>Amortizes PCIe transfer</td></tr></tbody></table><p>Override with environment variables:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VEX_NO_GPU</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.vx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # Force SIMD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VEX_FORCE_GPU</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.vx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # Force GPU</span></span></code></pre></div><h2 id="inline-fusion-vs-graph-functions" tabindex="-1">Inline Fusion vs Graph Functions <a class="header-anchor" href="#inline-fusion-vs-graph-functions" aria-label="Permalink to &quot;Inline Fusion vs Graph Functions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Inline Fusion <code>&lt;+ (a*b)</code></th><th>Graph Function</th></tr></thead><tbody><tr><td>Scope</td><td>Single expression</td><td>Entire function body</td></tr><tr><td>Fusion</td><td>Expression-level</td><td>Cross-statement</td></tr><tr><td>Control flow</td><td>No</td><td>if/else, for loops</td></tr><tr><td>Nesting</td><td>No</td><td>Graph calls graph fn</td></tr><tr><td>Use case</td><td>Quick one-liners</td><td>Complex algorithms</td></tr></tbody></table><p>Both work together: inline fusion expressions inside graph fn functions get fused into the larger graph.</p><h2 id="debug" tabindex="-1">Debug <a class="header-anchor" href="#debug" aria-label="Permalink to &quot;Debug&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VEX_FUSION_DEBUG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.vx</span></span></code></pre></div><p>Output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[GRAPH FN] dot: 3 SIR nodes → fused to 1 kernel</span></span>
<span class="line"><span>[GRAPH FN] Dispatch: SIMD (AVX-512, 8 lanes, unroll=2)</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VEX_GPU_DEBUG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.vx</span></span></code></pre></div><p>Output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[GRAPH FN] attention: 7 SIR nodes → 3 kernels (2 matmul + 1 fused)</span></span>
<span class="line"><span>[GRAPH FN] Dispatch: GPU Metal (Apple M2 Max)</span></span>
<span class="line"><span>[Metal] Kernel 1: matmul (256×256) → buffer_0</span></span>
<span class="line"><span>[Metal] Kernel 2: fused softmax → buffer_1</span></span>
<span class="line"><span>[Metal] Kernel 3: matmul → readback</span></span></code></pre></div>`,39)])])}const g=s(p,[["render",i]]);export{u as __pageData,g as default};
